select sapi.id as rowId ,puser.name as userName,sapi.branch as branch, csci.name as committeeName,sapi.committee_branch as committeeBranch, csy.name as yearName,sdept.name as deptName,suser.name as subUserName, sapi.sub_date as subDate,cspt.code as parttimeTypeName, cspj.name as positionName,sapi.create_time,suser1.name as creatorName, sapi.start_date as startDate,sapi.end_date as endDate,sapi.data_status as dataStatus from srm_ac_parttime_info sapi left join ct_srm_user puser on puser.id=sapi.user_id left join ct_srm_committee_info csci on csci.code=sapi.committee left join ct_srm_year csy on csy.code=sapi.year left join ct_srm_parttime_job cspj on cspj.code=sapi.position left join ct_srm_dept sdept on sdept.id=sapi.dept_id left join ct_srm_user suser on suser.id=sapi.sub_user_id left join ct_srm_user suser1 on suser1.id=sapi.creator_id left join ct_srm_parttime_type cspt on cspt.code=sapi.parttime_type where (sapi.sub_user_id=#{acParttimeInfoDto.userId} or sapi.user_id = #{acParttimeInfoDto.userId} or creator_id=#{acParttimeInfoDto.userId})
and sapi.data_status= #{acParttimeInfoDto.dataStatus}
and sapi.sub_date >= #{acParttimeInfoDto.startDate}
and sapi.sub_date <= #{acParttimeInfoDto.endDate}
and sapi.parttime_type = #{acParttimeInfoDto.parttimeType}
and sapi.committee = #{acParttimeInfoDto.committee}

