mapper.select:
select sapi.id as rowId ,puser.name as userName,sapi.branch as branch, csci.name as committeeName,sapi.committee_branch as committeeBranch, csy.name as yearName,sdept.name as deptName,suser.name as subUserName, sapi.sub_date as subDate, cspj.name as positionName,cspt.code as parttimeTypeName, sapi.start_date as startDate,sapi.end_date as endDate,sapi.data_status as dataStatus from srm_ac_parttime_info sapi left join ct_srm_user puser on puser.id=sapi.user_id left join ct_srm_committee_info csci on csci.code=sapi.committee left join ct_srm_year csy on csy.code=sapi.year left join ct_srm_parttime_job cspj on cspj.code=sapi.position left join ct_srm_dept sdept on sdept.id=sapi.dept_id left join ct_srm_user suser on suser.id=sapi.sub_user_id left join ct_srm_parttime_type cspt on cspt.code=sapi.parttime_type left join cf_srm_eaf_rec eafrec on eafrec.sys_no="T001" and eafrec.check_rec_id=sapi.id where eafrec.step_no>1
and sapi.parttime_type = #{acParttimeInfoDto.parttimeType}
and sapi.committee = #{acParttimeInfoDto.committee}
and sapi.user_id = #{acParttimeInfoDto.userId}
and sapi.sub_date >= #{acParttimeInfoDto.startDate}
and sapi.sub_date <= #{acParttimeInfoDto.endDate}
and ( (sapi.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeInfoDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where seafrec.sys_no="T001" and seafrec.check_rec_id=sapi.id) and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeInfoDto.userId}, '|%') and eafrec.check_datetime is not null) or (sapi.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeInfoDto.userId}, '|%')) )
and sapi.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeInfoDto.userId}, '|%')
and sapi.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeInfoDto.userId}, '|%')
and sapi.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{acParttimeInfoDto.userId}, '|%')

select sapt.id as id,puser.name as name from srm_ac_parttime_apply sapt
left join ct_srm_user puser on puser.id=sapi.user_id
left join cf_srm_eaf_rec eafrec on eafrec.sys_no=sapt.sys_no and eafrec.check_rec_id=sapt.id
where eafrec.step_no>1 and
( sapt.sub_user_id=#{userId}
or sapt.user_id=#{userId}
or sapt.create_user_id=#{userId}
)
and "2"=(select eafrec2.check_result from cf_srm_eaf_rec eafrec2 where eafrec2.sys_no=sapt.sys_no and eafrec2.check_rec_id=sapt.id order by eafrec2.step_no desc limit 1)
